      state.selectedItem === previousSelectedItemRef.current
        ? props.selectedItem
        : state.selectedItem
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [state.selectedItem, props.selectedItem])

  return [getState(state, props), dispatch]
}

